+#[test]
+fn test_build_record_fields_match_observation() {
+    let obs = shipped_obs("w-fields")
+        .with_output_equivalence(false)
+        .with_detail("my-detail");
+    let record = build_record(&obs);
+    assert_eq!(record.workload_id, "w-fields");
