+                "parity specimen '{}' should have materialized_ast_hash",
+                spec.specimen_id
+            );
+            assert!(
+                ev.original_ast_hash.is_some(),
+                "parity specimen '{}' should have original_ast_hash",
+                spec.specimen_id
+            );
+        }
+    }
+}
